CREATE INDEX ix_documents_source_file ON documents (source_file);  -- Also UNIQUE


-- =============================================================================
-- TABLE: chunks
-- Added in Phase 4 (commit 4aa59b5)
-- =============================================================================

-- Auto-generated single-column indexes
CREATE INDEX ix_chunks_doc_id       ON chunks (doc_id);
CREATE INDEX ix_chunks_page_number  ON chunks (page_number);

-- Composite/special indexes (__table_args__)
-- GIN index for PostgreSQL full-text search on TSVECTOR column
CREATE INDEX idx_chunks_tsv       ON chunks USING gin (tsv_content);
CREATE INDEX idx_chunks_doc_page  ON chunks (doc_id, page_number);


